import React, {useState, useRef, useEffect} from 'react';
import {createPortal} from 'react-dom';
import {
    Heart,
    Sparkles,
    Moon,
    Sun,
    Volume2,
    Zap,
    Calendar,
    Star,
    Smile,
    Coffee,
    Music,
    Flame,
    Cloud,
    Umbrella,
    Camera,
    Gift,
    Flower2,
    Feather,
    Palette,
    Rocket,
    Crown,
    Diamond,
    Cherry,
    Cake,
    IceCream,
    Pizza,
    Apple,
    Carrot,
    Cookie
} from 'lucide-react';

function CuteParameterCard() {
    const availableIcons = {
        Heart, Sparkles, Moon, Sun, Volume2, Zap, Calendar, Star, Smile, Coffee,
        Music, Flame, Cloud, Umbrella, Camera, Gift, Flower2, Feather, Palette,
        Rocket, Crown, Diamond, Cherry, Cake, IceCream, Pizza, Apple, Carrot, Cookie
    };

    // 可爱风格的主题色板
    const themeColors = [
        { name: '樱花粉', class: 'text-pink-500', bg: 'bg-pink-500', gradient: 'from-pink-400 to-pink-600' },
        { name: '薰衣草紫', class: 'text-purple-500', bg: 'bg-purple-500', gradient: 'from-purple-400 to-purple-600' },
        { name: '天空蓝', class: 'text-blue-500', bg: 'bg-blue-500', gradient: 'from-blue-400 to-blue-600' },
        { name: '薄荷绿', class: 'text-emerald-400', bg: 'bg-emerald-400', gradient: 'from-emerald-300 to-emerald-500' },
        { name: '蜜桃橙', class: 'text-orange-400', bg: 'bg-orange-400', gradient: 'from-orange-300 to-orange-500' },
        { name: '柠檬黄', class: 'text-yellow-500', bg: 'bg-yellow-500', gradient: 'from-yellow-400 to-yellow-600' },
        { name: '玫瑰红', class: 'text-rose-500', bg: 'bg-rose-500', gradient: 'from-rose-400 to-rose-600' },
        { name: '青柠绿', class: 'text-lime-500', bg: 'bg-lime-500', gradient: 'from-lime-400 to-lime-600' },
        { name: '水蓝色', class: 'text-cyan-500', bg: 'bg-cyan-500', gradient: 'from-cyan-400 to-cyan-600' },
        { name: '紫罗兰', class: 'text-violet-500', bg: 'bg-violet-500', gradient: 'from-violet-400 to-violet-600' },
        { name: '珊瑚粉', class: 'text-pink-400', bg: 'bg-pink-400', gradient: 'from-pink-300 to-pink-500' },
        { name: '蔷薇紫', class: 'text-fuchsia-500', bg: 'bg-fuchsia-500', gradient: 'from-fuchsia-400 to-fuchsia-600' }
    ];

    const [params, setParams] = useState({
        brightness: 75,
        volume: 60,
        speed: 3,
        hearts: 5,
        sparkle: true,
        theme: 'pink',
        energy: 80,
        cuteness: 100,
        dateCount: 0,
        mood: null,
        pendingMood: null
    });

    const [paramIcons, setParamIcons] = useState({
        brightness: 'Sun',
        volume: 'Volume2',
        speed: 'Zap',
        hearts: 'Heart',
        sparkle: 'Sparkles',
        theme: 'Moon',
        energy: 'Zap',
        dateCount: 'Calendar',
        mood: 'Star'
    });

    const [paramColors, setParamColors] = useState({
        brightness: 3, // 天空蓝
        volume: 1, // 薰衣草紫
        speed: 2, // 天空蓝
        hearts: 6, // 玫瑰红
        sparkle: 5, // 柠檬黄
        theme: 9, // 紫罗兰
        energy: 7, // 青柠绿
        dateCount: 0, // 樱花粉
        mood: 5 // 柠檬黄
    });

    const [iconPickerOpen, setIconPickerOpen] = useState(null);
    const [pickerPosition, setPickerPosition] = useState({top: 0, left: 0});
    const buttonRefs = useRef({});

    const updateParam = (key, value) => {
        setParams(prev => ({...prev, [key]: value}));
    };

    const updateIcon = (paramKey, iconName) => {
        setParamIcons(prev => ({...prev, [paramKey]: iconName}));
    };

    const updateColor = (paramKey, colorIndex) => {
        setParamColors(prev => ({...prev, [paramKey]: colorIndex}));
    };

    const handleDateClick = () => {
        updateParam('dateCount', params.dateCount + 1);
    };

    const handleMoodClick = (mood) => {
        if (params.pendingMood === mood) {
            updateParam('mood', mood);
            updateParam('pendingMood', null);
        } else {
            updateParam('pendingMood', mood);
            if (params.mood !== mood) {
                updateParam('mood', null);
            }
        }
    };

    const themes = {
        pink: 'from-pink-100 to-purple-100',
        blue: 'from-blue-100 to-cyan-100',
        peach: 'from-orange-100 to-pink-100'
    };

    const moods = [
        {value: 1, emoji: '😊', label: '开心'},
        {value: 2, emoji: '😍', label: '爱恋'},
        {value: 3, emoji: '🥰', label: '甜蜜'},
        {value: 4, emoji: '✨', label: '兴奋'},
        {value: 5, emoji: '💖', label: '幸福'}
    ];

    const handleIconClick = (paramKey) => {
        if (iconPickerOpen === paramKey) {
            setIconPickerOpen(null);
            return;
        }

        const button = buttonRefs.current[paramKey];
        if (button) {
            const rect = button.getBoundingClientRect();
            const viewportWidth = window.innerWidth;
            const pickerWidth = 320; // 增加宽度以容纳颜色选择器

            let left = rect.left + window.scrollX;

            // 如果选择器会超出右边界，则向左调整
            if (left + pickerWidth > viewportWidth) {
                left = viewportWidth - pickerWidth - 16;
            }

            setPickerPosition({
                top: rect.bottom + window.scrollY + 8,
                left: left
            });
            setIconPickerOpen(paramKey);
        }
    };

    // 图标和颜色选择器组件 - 使用 Portal
    const IconColorPicker = ({paramKey, currentIcon, currentColor, onSelectIcon, onSelectColor, onClose, position}) => {
        const pickerRef = useRef(null);
        const [activeTab, setActiveTab] = useState('icon');

        useEffect(() => {
            const handleClickOutside = (event) => {
                if (pickerRef.current && !pickerRef.current.contains(event.target)) {
                    const button = buttonRefs.current[paramKey];
                    if (button && !button.contains(event.target)) {
                        onClose();
                    }
                }
            };

            document.addEventListener('mousedown', handleClickOutside);
            return () => document.removeEventListener('mousedown', handleClickOutside);
        }, [paramKey, onClose]);

        return createPortal(
            <div
                ref={pickerRef}
                className="fixed z-[9999] bg-white rounded-2xl shadow-2xl border-2 border-pink-200 w-80"
                style={{top: `${position.top}px`, left: `${position.left}px`}}
            >
                {/* 标签页头部 */}
                <div className="flex border-b-2 border-pink-100">
                    <button
                        onClick={() => setActiveTab('icon')}
                        className={`flex-1 py-3 font-bold text-sm transition-all ${
                            activeTab === 'icon'
                                ? 'text-pink-600 bg-gradient-to-b from-pink-50 to-white border-b-2 border-pink-500'
                                : 'text-gray-400 hover:text-gray-600'
                        }`}
                    >
                        <Sparkles className="inline-block mr-1" size={14} />
                        选择图标
                    </button>
                    <button
                        onClick={() => setActiveTab('color')}
                        className={`flex-1 py-3 font-bold text-sm transition-all ${
                            activeTab === 'color'
                                ? 'text-pink-600 bg-gradient-to-b from-pink-50 to-white border-b-2 border-pink-500'
                                : 'text-gray-400 hover:text-gray-600'
                        }`}
                    >
                        <Palette className="inline-block mr-1" size={14} />
                        选择颜色
                    </button>
                </div>

                {/* 内容区域 */}
                <div className="p-4">
                    {activeTab === 'icon' ? (
                        <div className="space-y-3">
                            <div className="flex items-center justify-between">
                                <span className="text-sm font-bold text-gray-700">当前图标预览</span>
                                <div className={`p-2 rounded-lg bg-gradient-to-br ${themeColors[currentColor].gradient}`}>
                                    {React.createElement(availableIcons[currentIcon], { className: 'text-white', size: 24 })}
                                </div>
                            </div>
                            <div className="grid grid-cols-6 gap-2 max-h-64 overflow-y-auto pr-1 scrollbar-thin scrollbar-thumb-pink-200 scrollbar-track-gray-100">
                                {Object.entries(availableIcons).map(([name, Icon]) => (
                                    <button
                                        key={name}
                                        onClick={() => onSelectIcon(paramKey, name)}
                                        className={`p-2 rounded-lg transition-all hover:scale-110 ${
                                            currentIcon === name
                                                ? `bg-gradient-to-br ${themeColors[currentColor].gradient} text-white shadow-lg ring-2 ring-pink-300`
                                                : 'bg-gray-100 text-gray-600 hover:bg-pink-100'
                                        }`}
                                        title={name}
                                    >
                                        <Icon size={20}/>
                                    </button>
                                ))}
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-3">
                            <div className="flex items-center justify-between">
                                <span className="text-sm font-bold text-gray-700">当前颜色预览</span>
                                <div className={`p-2 rounded-lg bg-gradient-to-br ${themeColors[currentColor].gradient}`}>
                                    {React.createElement(availableIcons[currentIcon], { className: 'text-white', size: 24 })}
                                </div>
                            </div>
                            <div className="grid grid-cols-3 gap-3">
                                {themeColors.map((color, index) => (
                                    <button
                                        key={index}
                                        onClick={() => onSelectColor(paramKey, index)}
                                        className={`relative group transition-all hover:scale-105 ${
                                            currentColor === index ? 'scale-110' : ''
                                        }`}
                                    >
                                        <div className={`h-16 rounded-xl bg-gradient-to-br ${color.gradient} shadow-lg transition-all ${
                                            currentColor === index ? 'ring-4 ring-pink-300 shadow-xl' : 'hover:shadow-xl'
                                        }`}>
                                            <div className="h-full flex items-center justify-center">
                                                {React.createElement(availableIcons[currentIcon], { className: 'text-white', size: 28 })}
                                            </div>
                                        </div>
                                        <div className="mt-1 text-xs font-semibold text-gray-600 text-center">
                                            {color.name}
                                        </div>
                                        {currentColor === index && (
                                            <div className="absolute -top-1 -right-1">
                                                <Heart className="text-pink-500 fill-pink-500 animate-pulse" size={16}/>
                                            </div>
                                        )}
                                    </button>
                                ))}
                            </div>
                        </div>
                    )}
                </div>

                {/* 底部关闭按钮 */}
                <div className="border-t-2 border-pink-100 p-3">
                    <button
                        onClick={onClose}
                        className="w-full py-2 bg-gradient-to-r from-pink-400 to-purple-400 text-white font-bold rounded-xl hover:shadow-lg transition-all hover:scale-105"
                    >
                        完成 ♡
                    </button>
                </div>
            </div>,
            document.body
        );
    };

    // 带图标和颜色选择器的标题组件
    const ParamHeader = ({paramKey, label}) => {
        const IconComponent = availableIcons[paramIcons[paramKey]];
        const colorClass = themeColors[paramColors[paramKey]].class;

        return (
            <div className="flex items-center gap-2">
                <button
                    ref={(el) => buttonRefs.current[paramKey] = el}
                    onClick={() => handleIconClick(paramKey)}
                    className="group relative hover:scale-110 transition-transform"
                >
                    <IconComponent className={colorClass} size={20}/>
                    <div className="absolute -top-1 -right-1 w-2 h-2 bg-pink-400 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"/>
                </button>
                <span className="font-semibold text-gray-700">{label}</span>
            </div>
        );
    };

    return (
        <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-pink-50 via-purple-50 to-blue-50">
            <div className={`w-full max-w-md bg-gradient-to-br ${themes[params.theme]} rounded-3xl shadow-2xl p-6 space-y-4 border-4 border-white/50`}>

                {/* Header */}
                <div className="text-center mb-6">
                    <div className="flex items-center justify-center gap-2 mb-2">
                        <Sparkles className="text-pink-500" size={24}/>
                        <h2 className="text-2xl font-bold bg-gradient-to-r from-pink-500 to-purple-500 bg-clip-text text-transparent">
                            可爱参数面板
                        </h2>
                        <Sparkles className="text-purple-500" size={24}/>
                    </div>
                    <p className="text-sm text-gray-600">调整你的专属设置 ♡</p>
                    <p className="text-xs text-pink-400 mt-1">点击图标可更换图标和颜色哦 ~</p>
                </div>

                {/* Date Counter */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between">
                        <ParamHeader paramKey="dateCount" label="约会次数"/>
                        <div className="flex items-center gap-3">
                            <div className="flex items-center gap-1">
                                {[...Array(Math.min(params.dateCount, 5))].map((_, i) => (
                                    <Heart
                                        key={i}
                                        className="text-rose-400 fill-rose-400 animate-pulse"
                                        size={16}
                                        style={{animationDelay: `${i * 0.1}s`}}
                                    />
                                ))}
                            </div>
                            <span className="text-2xl font-bold text-rose-500 min-w-12 text-center">
                                {params.dateCount}
                            </span>
                            <button
                                onClick={handleDateClick}
                                className="group relative px-4 py-2 bg-gradient-to-r from-rose-400 to-pink-500 text-white font-bold rounded-xl hover:scale-110 active:scale-95 transition-all shadow-lg hover:shadow-xl"
                            >
                                <span className="relative z-10">+1</span>
                                <div className="absolute inset-0 bg-gradient-to-r from-rose-500 to-pink-600 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity"/>
                            </button>
                        </div>
                    </div>
                </div>

                {/* Mood Selector */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between mb-3">
                        <ParamHeader paramKey="mood" label="心情状态"/>
                        {params.pendingMood && (
                            <span className="text-xs text-pink-500 font-semibold animate-pulse">
                                再点一次确认 ♡
                            </span>
                        )}
                    </div>
                    <div className="flex gap-2">
                        {moods.map((mood) => {
                            const isPending = params.pendingMood === mood.value;
                            const isSelected = params.mood === mood.value;

                            return (
                                <button
                                    key={mood.value}
                                    onClick={() => handleMoodClick(mood.value)}
                                    className={`relative flex-1 py-3 rounded-xl font-bold transition-all ${
                                        isSelected
                                            ? 'bg-gradient-to-r from-pink-500 to-rose-500 text-white shadow-xl scale-110 ring-4 ring-pink-300'
                                            : isPending
                                                ? 'bg-gradient-to-r from-pink-300 to-rose-300 text-white shadow-lg scale-105 ring-2 ring-pink-400 animate-pulse'
                                                : 'bg-white/80 text-gray-600 hover:bg-white hover:scale-105'
                                    }`}
                                >
                                    <div className="flex flex-col items-center gap-1">
                                        <span className="text-lg">{mood.emoji}</span>
                                        <span className="text-xs">{mood.label}</span>
                                    </div>
                                    {isPending && (
                                        <div className="absolute -top-1 -right-1 w-3 h-3 bg-pink-500 rounded-full animate-ping"/>
                                    )}
                                    {isSelected && (
                                        <div className="absolute -top-1 -right-1">
                                            <Heart className="text-white fill-white" size={12}/>
                                        </div>
                                    )}
                                </button>
                            );
                        })}
                    </div>
                </div>

                {/* Brightness */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between mb-2">
                        <ParamHeader paramKey="brightness" label="亮度"/>
                        <span className={`text-sm font-bold ${themeColors[paramColors.brightness].class}`}>
                            {params.brightness}%
                        </span>
                    </div>
                    <input
                        type="range"
                        min="0"
                        max="100"
                        value={params.brightness}
                        onChange={(e) => updateParam('brightness', parseInt(e.target.value))}
                        className={`w-full h-2 bg-gradient-to-r ${themeColors[paramColors.brightness].gradient} rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:shadow-lg [&::-webkit-slider-thumb]:border-2 [&::-webkit-slider-thumb]:border-pink-400`}
                    />
                </div>

                {/* Volume */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between mb-2">
                        <ParamHeader paramKey="volume" label="音量"/>
                        <span className={`text-sm font-bold ${themeColors[paramColors.volume].class}`}>
                            {params.volume}%
                        </span>
                    </div>
                    <input
                        type="range"
                        min="0"
                        max="100"
                        value={params.volume}
                        onChange={(e) => updateParam('volume', parseInt(e.target.value))}
                        className={`w-full h-2 bg-gradient-to-r ${themeColors[paramColors.volume].gradient} rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:shadow-lg [&::-webkit-slider-thumb]:border-2 [&::-webkit-slider-thumb]:border-pink-400`}
                    />
                </div>

                {/* Speed */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between mb-3">
                        <ParamHeader paramKey="speed" label="速度"/>
                    </div>
                    <div className="flex gap-2">
                        {[1, 2, 3, 4, 5].map((speed) => (
                            <button
                                key={speed}
                                onClick={() => updateParam('speed', speed)}
                                className={`flex-1 py-2 rounded-xl font-bold transition-all ${
                                    params.speed === speed
                                        ? `bg-gradient-to-r ${themeColors[paramColors.speed].gradient} text-white shadow-lg scale-110`
                                        : 'bg-white/80 text-gray-600 hover:bg-white hover:scale-105'
                                }`}
                            >
                                {speed}
                            </button>
                        ))}
                    </div>
                </div>

                {/* Hearts Counter */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between">
                        <ParamHeader paramKey="hearts" label="爱心数量"/>
                        <div className="flex items-center gap-2">
                            <button
                                onClick={() => updateParam('hearts', Math.max(0, params.hearts - 1))}
                                className={`w-8 h-8 rounded-full bg-gradient-to-r ${themeColors[paramColors.hearts].gradient} text-white font-bold hover:scale-110 transition-transform shadow-md`}
                            >
                                −
                            </button>
                            <span className={`text-lg font-bold ${themeColors[paramColors.hearts].class} w-8 text-center`}>
                                {params.hearts}
                            </span>
                            <button
                                onClick={() => updateParam('hearts', Math.min(10, params.hearts + 1))}
                                className={`w-8 h-8 rounded-full bg-gradient-to-r ${themeColors[paramColors.hearts].gradient} text-white font-bold hover:scale-110 transition-transform shadow-md`}
                            >
                                +
                            </button>
                        </div>
                    </div>
                </div>

                {/* Sparkle Toggle */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between">
                        <ParamHeader paramKey="sparkle" label="闪闪特效"/>
                        <button
                            onClick={() => updateParam('sparkle', !params.sparkle)}
                            className={`w-14 h-7 rounded-full transition-all shadow-inner ${
                                params.sparkle ? `bg-gradient-to-r ${themeColors[paramColors.sparkle].gradient}` : 'bg-gray-300'
                            }`}
                        >
                            <div
                                className={`w-6 h-6 bg-white rounded-full shadow-lg transition-transform ${
                                    params.sparkle ? 'translate-x-7' : 'translate-x-0.5'
                                }`}
                            />
                        </button>
                    </div>
                </div>

                {/* Theme Selection */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center gap-2 mb-3">
                        <ParamHeader paramKey="theme" label="主题色彩"/>
                    </div>
                    <div className="flex gap-2">
                        <button
                            onClick={() => updateParam('theme', 'pink')}
                            className={`flex-1 h-10 rounded-xl bg-gradient-to-r from-pink-300 to-purple-300 transition-all ${
                                params.theme === 'pink' ? 'ring-4 ring-pink-400 scale-105 shadow-lg' : 'hover:scale-105'
                            }`}
                        />
                        <button
                            onClick={() => updateParam('theme', 'blue')}
                            className={`flex-1 h-10 rounded-xl bg-gradient-to-r from-blue-300 to-cyan-300 transition-all ${
                                params.theme === 'blue' ? 'ring-4 ring-blue-400 scale-105 shadow-lg' : 'hover:scale-105'
                            }`}
                        />
                        <button
                            onClick={() => updateParam('theme', 'peach')}
                            className={`flex-1 h-10 rounded-xl bg-gradient-to-r from-orange-300 to-pink-300 transition-all ${
                                params.theme === 'peach' ? 'ring-4 ring-orange-400 scale-105 shadow-lg' : 'hover:scale-105'
                            }`}
                        />
                    </div>
                </div>

                {/* Energy Input */}
                <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
                    <div className="flex items-center justify-between">
                        <ParamHeader paramKey="energy" label="能量值"/>
                        <input
                            type="number"
                            min="0"
                            max="100"
                            value={params.energy}
                            onChange={(e) => updateParam('energy', Math.min(100, Math.max(0, parseInt(e.target.value) || 0)))}
                            className={`w-20 px-3 py-2 bg-white rounded-xl border-2 ${themeColors[paramColors.energy].bg} border-opacity-30 text-center font-bold ${themeColors[paramColors.energy].class} focus:outline-none focus:ring-2 focus:ring-pink-400 focus:border-transparent`}
                        />
                    </div>
                </div>

                {/* Footer */}
                <div className="text-center pt-4">
                    <p className="text-xs text-gray-500">♡ 愿你每天都充满快乐 ♡</p>
                </div>
            </div>

            {/* 图标和颜色选择器 Portal */}
            {iconPickerOpen && (
                <IconColorPicker
                    paramKey={iconPickerOpen}
                    currentIcon={paramIcons[iconPickerOpen]}
                    currentColor={paramColors[iconPickerOpen]}
                    onSelectIcon={updateIcon}
                    onSelectColor={updateColor}
                    onClose={() => setIconPickerOpen(null)}
                    position={pickerPosition}
                />
            )}
        </div>
    );
}

export default CuteParameterCard;
